COPY about FROM 'data/output/csv/about.csv' (FORMAT 'csv', force_not_null ('value', 'key'), quote '"', delimiter ',', header 1);
COPY categorie_detention FROM 'data/output/csv/categorie_detention.csv' (FORMAT 'csv', force_not_null ('categorie_detention_id', 'libelle', 'gamme_detention'), quote '"', delimiter ',', header 1);
COPY famille_metier FROM 'data/output/csv/famille_metier.csv' (FORMAT 'csv', force_not_null ('famille_metier_id', 'libelle'), quote '"', delimiter ',', header 1);
COPY groupe_competence FROM 'data/output/csv/groupe_competence.csv' (FORMAT 'csv', force_not_null ('groupe_competence_id', 'libelle'), quote '"', delimiter ',', header 1);
COPY referentiel_competence FROM 'data/output/csv/referentiel_competence.csv' (FORMAT 'csv', force_not_null ('referentiel_competence_id', 'libelle', 'type_referentiel', 'type_referentiel_detaille'), quote '"', delimiter ',', header 1);
COPY statut_metier FROM 'data/output/csv/statut_metier.csv' (FORMAT 'csv', force_not_null ('libelle', 'statut_metier_id'), quote '"', delimiter ',', header 1);
COPY competence FROM 'data/output/csv/competence.csv' (FORMAT 'csv', force_not_null ('code_competence', 'neobrain_competence_id', 'groupe_competence_id', 'referentiel_competence_id'), quote '"', delimiter ',', header 1);
COPY competence_utilisateur FROM 'data/output/csv/competence_utilisateur.csv' (FORMAT 'csv', force_not_null ('code_competence', 'nom_competence', 'categorie_detention_id', 'date_mise_a_jour'), quote '"', delimiter ',', header 1);
COPY famille_metier_couleur FROM 'data/output/csv/famille_metier_couleur.csv' (FORMAT 'csv', force_not_null ('famille_metier_id', 'couleur_hex'), quote '"', delimiter ',', header 1);
COPY metier FROM 'data/output/csv/metier.csv' (FORMAT 'csv', force_not_null ('code_metier', 'neobrain_metier_id', 'metier_collaborateur', 'famille_metier_id', 'statut_metier_id', 'metier_actif'), quote '"', delimiter ',', header 1);
COPY metier_competence FROM 'data/output/csv/metier_competence.csv' (FORMAT 'csv', force_not_null ('code_metier', 'code_competence', 'nom_competence', 'poids', 'niveau_requis', 'est_actif', 'date_creation', 'date_mise_a_jour'), quote '"', delimiter ',', header 1);
COPY niveau_description_competence FROM 'data/output/csv/niveau_description_competence.csv' (FORMAT 'csv', force_not_null ('code_competence', 'niveau', 'description'), quote '"', delimiter ',', header 1);
